def normalize_path(path):
    if not path:
        return '/'

    # Split by '/'
    parts = path.split('/')

    stack = []
    for part in parts:
        if part == '' or part == '.':
            continue
        elif part == '..':
            if stack:
                stack.pop()
        else:
            stack.append(part)

    return '/' + '/'.join(stack)

def longest_valid_parentheses(s):
    stack = [-1]
    max_len = 0
    for i, char in enumerate(s):
        if char == '(':
            stack.append(i)
        else:
            stack.pop()
            if not stack:
                stack.append(i)
            else:
                max_len = max(max_len, i - stack[-1])
    return max_len

def min_meeting_rooms(intervals):
    if not intervals:
        return 0

    # Separate start and end times
    starts = sorted([interval[0] for interval in intervals])
    ends = sorted([interval[1] for interval in intervals])

    rooms = 0
    end_ptr = 0

    for start in starts:
        if start >= ends[end_ptr]:
            # A room has been freed
            end_ptr += 1
        else:
            # Need a new room
            rooms += 1

    return rooms
